package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import com.google.gson.GsonBuilder;
import java.lang.reflect.Field;

public class GsonBuilderTest {

  @Test
  public void testSetDateFormat_withValidPattern_shouldSetDatePatternField() throws Exception {
    GsonBuilder builder = new GsonBuilder();
    String pattern = "yyyy-MM-dd";

    GsonBuilder returned = builder.setDateFormat(pattern);

    // Verify the method returns the same instance (for chaining)
    assertSame(builder, returned);

    // Use reflection to access the private datePattern field
    Field datePatternField = GsonBuilder.class.getDeclaredField("datePattern");
    datePatternField.setAccessible(true);
    String actualPattern = (String) datePatternField.get(builder);

    assertEquals(pattern, actualPattern);
  }

  @Test
  public void testSetDateFormat_withNullPattern_shouldSetDatePatternFieldToNull() throws Exception {
    GsonBuilder builder = new GsonBuilder();

    GsonBuilder returned = builder.setDateFormat(null);

    assertSame(builder, returned);

    Field datePatternField = GsonBuilder.class.getDeclaredField("datePattern");
    datePatternField.setAccessible(true);
    String actualPattern = (String) datePatternField.get(builder);

    assertNull(actualPattern);
  }
}
